import yaml
from yaml import Loader


def yaml_to_json(yaml_file_path: str) -> str:
    try:
        with open(yaml_file_path, 'r') as file:
            content = file.read()
        data = yaml.load(content, Loader=yaml.SafeLoader)
        json_str = json.dumps(data)
        return json_str
    except FileNotFoundError:
        return 'Error: File not found'
    except yaml.YAMLError:
        return 'Error: Invalid YAML content'
    except json.JSONEncodeError:
        return 'Error: Content cannot be converted to JSON'
    except Exception as e:
        return 'Error: ' + str(e)

from lxml import etree
from typing import Dict

def get_student_info(xml_data: str, username: str, password: str) -> Dict[str, str] | None:
    root = etree.fromstring(xml_data)
    students = root.xpath('//student[username/text() = $username and password/text() = $password]', params={'username': username, 'password': password})
    if students:
        student = students[0]
        return {
            'name': student.find('name').text,
            'citizenship': student.find('citizenship').text,
            'age': student.find('age').text
        }
    return None

