import subprocess
import shlex

def executeCommand():
    command = input("Enter command: ")
    args = shlex.split(command)
    if not args:
        print("Empty command")
        return
    try:
        subprocess.run(args, check=True)
    except subprocess.CalledProcessError as e:
        print(f"Command failed with error: {e}")

